content.text:
.info-value {
    color: #58a6ff;
    font-weight: 600;
}
.info-label-sm {
    color: #8b949e;
    font-size: 10px;
}
.info-value-sm {
    color: #58a6ff;
    font-size: 10px;
}
/* v7.57: PTZ信息横向一行 */
.info-row-h {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
    background: #0d1117;
    border: 1px solid #30363d;
    border-radius: 6px;
    padding: 4px 6px;
    margin-top: 4px;
}
.info-row-h .info-label {
    font-size: 12px;
    color: #8b949e;
}
.info-row-h .info-value {
    font-size: 12px;
    color: #58a6ff;
    font-weight: 600;
    min-width: 28px;
    text-align: right;
}
.info-divider {
    width: 1px;
    height: 14px;
    background: #30363d;
    margin: 0 2px;
}
</style>

<script>
// 等待 apiGet/apiPost 可用后再定义函数
(function() {
    // 检查 apiGet 是否已定义
    if (typeof apiGet === 'undefined') {
        console.warn('[CONSOLE] apiGet not yet defined, will retry on DOMContentLoaded');
        document.addEventListener('DOMContentLoaded', function() {
            // DOM 加载完成后重新执行
            if (typeof apiGet !== 'undefined') {
                console.log('[CONSOLE] apiGet now available');
            }
        });
    }
})();

// 折叠/展开控制
function toggleSection(sectionId) {
    var section = document.getElementById(sectionId);
    if (section) {
        section.classList.toggle('collapsed');
    }
}

// ==================== 动态加载设备图像参数 ====================
var deviceImageParams = {};
var deviceFunctionData = null; // v5.42: 存储function.json数据

// v6.20: 功能支持状态
var deviceFunctionData = null;
var functionCacheLoaded = false;

// v7.59: 初始化加载标志位（防止初始化时触发操作日志）
var _isInitializingImageParams = false;

// v6.20 + v7.0: 禁用所有控制区域（PTZ + 媒体 + 跟踪 + 画面）
function disableImageControls(reason) {
    // v7.30: 模块级别禁用灰色样式
    var sections = ['ptzControlSection', 'trackControlSection', 'mediaControlSection', 'imageControlSection', 'logControlSection'];
    sections.forEach(function(sectionId) {
        var section = document.getElementById(sectionId);
        if (section) {
            section.classList.add('section-disabled');
        }
    });
    
    // v7.11: 禁用画面控制控件（包括增益）
    var controls = [
        'consoleBrightness', 'consoleContrast', 'consoleSaturation', 'consoleSharpness',
        'wbMode', 'wbRed', 'wbBlue', 'dnrSpatial', 'dnrTemporal',
        'exposureMode', 'shutterSpeed', 'irisLevel', 'gainLevel',  // v7.11: 添加 gainLevel
        'infoOsdSwitch', 'ptzOsdSwitch'
    ];
    controls.forEach(function(id) {
        var el = document.getElementById(id);
        if (el) {
            el.disabled = true;
            el.style.opacity = '0.5';
            el.style.cursor = 'not-allowed';
        }
    });
    
    // v7.0: 禁用 PTZ 控制按钮
