// 白平衡模式切换：显示/隐藏对应控件
function onWbModeChange(mode) {
    var manualControls = document.getElementById('wbManualControls');
    var localControls = document.getElementById('wbLocalControls');
    var wbRed = document.getElementById('wbRed');
    var wbBlue = document.getElementById('wbBlue');

    if (mode === 'manual') {
        if (manualControls) manualControls.style.display = 'flex';
        if (localControls) localControls.style.display = 'none';
        if (wbRed) wbRed.disabled = false;
        if (wbBlue) wbBlue.disabled = false;
        setWhiteBalanceMode('manual');
    } else if (mode === 'local') {
        if (manualControls) manualControls.style.display = 'none';
        if (localControls) localControls.style.display = 'block';
        if (wbRed) wbRed.disabled = true;
        if (wbBlue) wbBlue.disabled = true;
    } else {
        // 自动
        if (manualControls) manualControls.style.display = 'none';
        if (localControls) localControls.style.display = 'none';
        if (wbRed) wbRed.disabled = true;
        if (wbBlue) wbBlue.disabled = true;
        setWhiteBalanceMode('auto');
    }
}

// 停止自动白平衡
function stopAutoWhiteBalance() {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    // 调用后端停止接口
    apiPost('/api/v1/ptz/' + dev + '/whitebalance/stop', {}).then(function(r) {
        if (r && r.success) {
            showToast('success', '已停止自动白平衡');
            if (typeof operationLog === 'function') operationLog('停止自动白平衡', 'success');
        }
    }).catch(function(e) {
        showToast('error', '停止失败');
    });
    // 恢复按钮状态
    var stopBtn = document.getElementById('btnWbLocalStop');
    var selectBtn = document.getElementById('btnWbRegionSelect');
    if (stopBtn) stopBtn.style.display = 'none';
    if (selectBtn) { selectBtn.textContent = '框选'; selectBtn.classList.remove('btn-danger'); selectBtn.classList.add('btn-secondary'); }
}

// 对焦模式切换：显示/隐藏对应控件
function onFocusModeChange(mode) {
    var moveControls = document.getElementById('focusMoveControls');
    var localControls = document.getElementById('focusLocalControls');

    if (mode === 'manual') {
        if (moveControls) moveControls.style.display = 'block';
        if (localControls) localControls.style.display = 'none';
        setFocusMode('manual');
    } else if (mode === 'local') {
        if (moveControls) moveControls.style.display = 'none';
        if (localControls) localControls.style.display = 'block';
    } else {
        // 自动
        if (moveControls) moveControls.style.display = 'none';
        if (localControls) localControls.style.display = 'none';
        setFocusMode('auto');
    }
}

// 停止自动对焦
function stopAutoFocus() {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPost('/api/v1/ptz/' + dev + '/focus/stop', {}).then(function(r) {
        if (r && r.success) {
            showToast('success', '已停止自动对焦');
            if (typeof operationLog === 'function') operationLog('停止自动对焦', 'success');
        }
    }).catch(function(e) {
        showToast('error', '停止失败');
    });
    var stopBtn = document.getElementById('btnFocusLocalStop');
    var selectBtn = document.getElementById('btnFocusRegionSelect');
    if (stopBtn) stopBtn.style.display = 'none';
    if (selectBtn) { selectBtn.textContent = '框选'; selectBtn.classList.remove('btn-danger'); selectBtn.classList.add('btn-secondary'); }
}

