"""
v8.38 Playwright E2E 验证脚本
验证主控台界面修改：
1. 左侧运动控制：PTZ OSD 开关存在，变焦/对焦区已移除
2. 右侧画面控制：布局顺序正确
3. 白平衡下拉：3选项（自动/手动/局部）
4. 白平衡手动模式：R/B滑动条显示
5. 白平衡局部模式：框选+定时显示
6. 对焦下拉：3选项（自动/手动/局部）
7. 对焦手动模式：焦点移动按钮显示
8. 对焦局部模式：框选+定时显示
9. 降噪位于饱和度/锐度下方
10. OSD控制区无PTZ开关（仅信息）
"""
import asyncio
import sys
import os

async def main():
    from playwright.async_api import async_playwright

    errors = []
    passed = []

    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True)
        page = await browser.new_page()

        # 拦截 console 错误
        console_errors = []
        page.on("console", lambda msg: console_errors.append(f"[{msg.type}] {msg.text}") if msg.type == "error" else None)

        # 拦截 request 失败
        request_errors = []
        page.on("requestfailed", lambda req: request_errors.append(f"{req.url} - {req.failure}"))

        # 导航到主控台页面
        await page.goto("http://127.0.0.1:10280/", wait_until="networkidle", timeout=15000)

        # 切换到主控台页面
        console_btn = page.locator('[data-page="console"]')
        if await console_btn.count() > 0:
            await console_btn.click()
            await page.wait_for_timeout(500)
        else:
            errors.append("无法找到主控台导航按钮")

        # ========== 测试1: 左侧运动控制 - PTZ OSD 开关存在 ==========
        try:
            ptz_osd_switch = page.locator('#ptzOsdSwitchInPtz')
            if await ptz_osd_switch.count() > 0:
                passed.append("✅ 测试1: 左侧面板 PTZ OSD 开关存在")
            else:
                errors.append("❌ 测试1: 左侧面板未找到 PTZ OSD 开关 (ptzOsdSwitchInPtz)")
        except Exception as e:
            errors.append(f"❌ 测试1异常: {e}")

        # ========== 测试2: 左侧运动控制 - 旧的变焦/对焦区已移除 ==========
        try:
            # 检查运动控制区内不应有 focusMode select（旧的）
            ptz_section = page.locator('#ptzControlSection')
            old_focus_select = ptz_section.locator('select#focusMode')
            if await old_focus_select.count() == 0:
                passed.append("✅ 测试2: 左侧面板变焦/对焦区已移除（无focusMode select）")
            else:
                errors.append("❌ 测试2: 左侧面板仍存在 focusMode select")
        except Exception as e:
            errors.append(f"❌ 测试2异常: {e}")

        # ========== 测试3: 左侧运动控制 - 旧的焦距按钮已移除 ==========
        try:
            ptz_section = page.locator('#ptzControlSection')
            # 检查不应该有 ptzZoom 调用（焦距按钮）
            zoom_btns = ptz_section.locator('button[onmousedown*="ptzZoom"]')
            if await zoom_btns.count() == 0:
                passed.append("✅ 测试3: 左侧面板焦距按钮已移除")
            else:
                errors.append(f"❌ 测试3: 左侧面板仍存在 {await zoom_btns.count()} 个焦距按钮")
        except Exception as e:
            errors.append(f"❌ 测试3异常: {e}")

        # ========== 测试4: 右侧画面控制 - 白平衡下拉3选项 ==========
        try:
            wb_select = page.locator('#wbMode')
            if await wb_select.count() > 0:
                options = await wb_select.locator('option').all()
                opt_values = []
                for opt in options:
                    opt_values.append(await opt.get_attribute('value'))

                expected = ['auto', 'manual', 'local']
                if opt_values == expected:
                    passed.append(f"✅ 测试4: 白平衡下拉选项正确: {opt_values}")
                else:
                    errors.append(f"❌ 测试4: 白平衡下拉选项不符: 期望{expected}, 实际{opt_values}")
            else:
                errors.append("❌ 测试4: 未找到白平衡下拉 (wbMode)")
        except Exception as e:
            errors.append(f"❌ 测试4异常: {e}")

        # ========== 测试5: 白平衡 - R/B滑动条默认隐藏 ==========
        try:
            wb_manual = page.locator('#wbManualControls')
            if await wb_manual.count() > 0:
                display_val = await wb_manual.get_attribute('style')
                if 'display:none' in display_val or 'display: none' in display_val:
                    passed.append("✅ 测试5: 白平衡R/B滑动条默认隐藏")
                else:
                    errors.append(f"❌ 测试5: 白平衡R/B滑动条未隐藏: style={display_val}")
            else:
                errors.append("❌ 测试5: 未找到 wbManualControls")
        except Exception as e:
            errors.append(f"❌ 测试5异常: {e}")

        # ========== 测试6: 白平衡 - 局部控制默认隐藏 ==========
        try:
            wb_local = page.locator('#wbLocalControls')
            if await wb_local.count() > 0:
                display_val = await wb_local.get_attribute('style')
                if 'display:none' in display_val or 'display: none' in display_val:
                    passed.append("✅ 测试6: 白平衡局部控制默认隐藏")
                else:
                    errors.append(f"❌ 测试6: 白平衡局部控制未隐藏: style={display_val}")
            else:
                errors.append("❌ 测试6: 未找到 wbLocalControls")
        except Exception as e:
            errors.append(f"❌ 测试6异常: {e}")

        # ========== 测试7: 白平衡 - 切换到手动模式，R/B显示 ==========
        try:
            await page.select_option('#wbMode', 'manual')
            await page.wait_for_timeout(300)

            wb_manual = page.locator('#wbManualControls')
            display_val = await wb_manual.get_attribute('style')
            if 'display:none' not in display_val and 'display: none' not in display_val:
                passed.append("✅ 测试7: 白平衡手动模式 → R/B滑动条显示")
            else:
                errors.append(f"❌ 测试7: 白平衡手动模式 R/B仍未显示: style={display_val}")

            # 同时验证局部控制隐藏
            wb_local = page.locator('#wbLocalControls')
            local_display = await wb_local.get_attribute('style')
            if 'display:none' in local_display or 'display: none' in local_display:
                pass  # 正确：局部应隐藏
            else:
                errors.append(f"❌ 测试7b: 白平衡手动模式 → 局部控制未隐藏")
        except Exception as e:
            errors.append(f"❌ 测试7异常: {e}")

        # ========== 测试8: 白平衡 - 切换到局部模式 ==========
        try:
            await page.select_option('#wbMode', 'local')
            await page.wait_for_timeout(300)

            wb_local = page.locator('#wbLocalControls')
            local_display = await wb_local.get_attribute('style')
            if 'display:none' not in local_display and 'display: none' not in local_display:
                passed.append("✅ 测试8: 白平衡局部模式 → 局部控制显示")
            else:
                errors.append(f"❌ 测试8: 白平衡局部模式 控制未显示: style={local_display}")

            # R/B 应隐藏
            wb_manual = page.locator('#wbManualControls')
            manual_display = await wb_manual.get_attribute('style')
            if 'display:none' in manual_display or 'display: none' in manual_display:
                pass  # 正确
            else:
                errors.append(f"❌ 测试8b: 白平衡局部模式 → R/B未隐藏")

            # 验证框选按钮存在
            btn_wb_region = page.locator('#btnWbRegionSelect')
            if await btn_wb_region.count() > 0:
                btn_text = await btn_wb_region.text_content()
                if '框选' in btn_text:
                    pass  # 正确
                else:
                    errors.append(f"❌ 测试8c: 白平衡框选按钮文字错误: '{btn_text}'")
            else:
                errors.append("❌ 测试8c: 未找到白平衡框选按钮")

            # 验证定时输入框存在
            wb_timer = page.locator('#wbTimerInput')
            if await wb_timer.count() > 0:
                timer_val = await wb_timer.get_attribute('value')
                if timer_val == '0':
                    pass  # 正确：默认0
                else:
                    errors.append(f"❌ 测试8d: 白平衡定时默认值错误: {timer_val}")
            else:
                errors.append("❌ 测试8d: 未找到白平衡定时输入框")

            # 验证停止按钮存在且隐藏
            wb_stop = page.locator('#btnWbLocalStop')
            if await wb_stop.count() > 0:
                stop_display = await wb_stop.get_attribute('style')
                if 'display:none' in stop_display or 'display: none' in stop_display:
                    pass  # 正确：默认隐藏
                else:
                    errors.append(f"❌ 测试8e: 白平衡停止按钮未隐藏")
            else:
                errors.append("❌ 测试8e: 未找到白平衡停止按钮")

        except Exception as e:
            errors.append(f"❌ 测试8异常: {e}")

        # ========== 测试9: 白平衡 - 切回自动，所有附加控件隐藏 ==========
        try:
            await page.select_option('#wbMode', 'auto')
            await page.wait_for_timeout(300)

            wb_manual = page.locator('#wbManualControls')
            manual_display = await wb_manual.get_attribute('style')
            wb_local = page.locator('#wbLocalControls')
            local_display = await wb_local.get_attribute('style')

            if ('display:none' in manual_display or 'display: none' in manual_display) and \
               ('display:none' in local_display or 'display: none' in local_display):
                passed.append("✅ 测试9: 白平衡自动模式 → 所有附加控件隐藏")
            else:
                errors.append(f"❌ 测试9: 白平衡自动模式 控件未全部隐藏")
        except Exception as e:
            errors.append(f"❌ 测试9异常: {e}")

        # ========== 测试10: 对焦下拉3选项 ==========
        try:
            focus_select = page.locator('#focusMode')
            if await focus_select.count() > 0:
                options = await focus_select.locator('option').all()
                opt_values = []
                for opt in options:
                    opt_values.append(await opt.get_attribute('value'))

                expected = ['auto', 'manual', 'local']
                if opt_values == expected:
                    passed.append(f"✅ 测试10: 对焦下拉选项正确: {opt_values}")
                else:
                    errors.append(f"❌ 测试10: 对焦下拉选项不符: 期望{expected}, 实际{opt_values}")
            else:
                errors.append("❌ 测试10: 未找到对焦下拉 (focusMode)")
        except Exception as e:
            errors.append(f"❌ 测试10异常: {e}")

        # ========== 测试11: 对焦 - 焦点移动按钮默认隐藏 ==========
        try:
            focus_move = page.locator('#focusMoveControls')
            if await focus_move.count() > 0:
                display_val = await focus_move.get_attribute('style')
                if 'display:none' in display_val or 'display: none' in display_val:
                    passed.append("✅ 测试11: 对焦焦点移动按钮默认隐藏")
                else:
                    errors.append(f"❌ 测试11: 焦点移动按钮未隐藏: style={display_val}")
            else:
                errors.append("❌ 测试11: 未找到 focusMoveControls")
        except Exception as e:
            errors.append(f"❌ 测试11异常: {e}")

        # ========== 测试12: 对焦 - 切换到手动模式，焦点按钮显示 ==========
        try:
            await page.select_option('#focusMode', 'manual')
            await page.wait_for_timeout(300)

            focus_move = page.locator('#focusMoveControls')
            display_val = await focus_move.get_attribute('style')
            if 'display:none' not in display_val and 'display: none' not in display_val:
