    function _getOverlayPos(e) {
        var overlay = document.getElementById('regionOverlay');
        var rect = overlay.getBoundingClientRect();
        return { x: e.clientX - rect.left, y: e.clientY - rect.top };
    }

    // v8.11: 统一 ISAPI 截图 → 后端裁剪 → 迭代搜索 → 操作日志
    function _finishRegion() {
        var overlay = document.getElementById('regionOverlay');
        var box = document.getElementById('regionBox');
        var dev = window.connectedDevice;
        if (!dev || !dev.ip) { showToast('error', '未连接设备'); _resetRegionUI(); return; }

        var ow = overlay.offsetWidth, oh = overlay.offsetHeight;
        var sx = parseInt(box.style.left) / ow;
        var sy = parseInt(box.style.top) / oh;
        var sw = parseInt(box.style.width) / ow;
        var sh = parseInt(box.style.height) / oh;
        if (sw < 0.01 || sh < 0.01) { showToast('warning', '框选区域太小'); _resetRegionUI(); return; }

        var mode = _regionMode;
        var endpoint = mode === 'whitebalance' ? '/api/v1/vision/whitebalance-search'
                                               : '/api/v1/vision/focus-search';
        var label = mode === 'whitebalance' ? '白平衡' : '对焦';

        _resetRegionUI();
        showToast('info', label + '迭代中...');
        operationLog('── ' + label + '迭代开始 ──', 'info');

        // SSE 流式调用
        var body = JSON.stringify({ x: sx, y: sy, w: sw, h: sh });
        fetch(endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: body })
            .then(function(resp) {
                if (!resp.ok) throw new Error('HTTP ' + resp.status);
                var reader = resp.body.getReader();
                var decoder = new TextDecoder();
                var buf = '';
                function pump() {
                    return reader.read().then(function(r) {
                        if (r.done) return;
                        buf += decoder.decode(r.value, { stream: true });
                        // 按 \n\n 分割事件
                        var parts = buf.split('\n\n');
                        buf = parts.pop();  // 最后一段可能不完整
                        for (var i = 0; i < parts.length; i++) {
                            var line = parts[i];
                            if (!line.startsWith('data: ')) continue;
                            try {
                                var ev = JSON.parse(line.slice(6));
                                if (ev.type === 'start') {
                                    operationLog(label + '开始, ' + ev.crop, 'info');
                                } else if (ev.type === 'wb') {
                                    operationLog('调整 #' + ev.step + ': ' + ev.stage
                                        + ' R=' + ev.red_gain + ' B=' + ev.blue_gain
                                        + ' → R=' + ev.r_avg + ' G=' + ev.g_avg + ' B=' + ev.b_avg
                                        + ' (Δ=' + ev.delta + ')', 'debug');
                                } else if (ev.type === 'focus') {
                                    operationLog('对焦 #' + ev.step + ': ' + ev.stage
                                        + ' ' + ev.action + ' 反差=' + ev.contrast
                                        + ' (' + ev.duration + 's) ' + ev.message, 'debug');
                                } else if (ev.type === 'done') {
                                    if (ev.final_red !== undefined) {
                                        showToast('success', label + '完成 R=' + ev.final_red + ' B=' + ev.final_blue);
                                        operationLog('── ' + label + '完成: R=' + ev.final_red + ' B=' + ev.final_blue + ' (' + ev.total_steps + '步) ──', 'success');
                                        // 刷新主控台白平衡滑动条
                                        var wbRed = document.getElementById('wbRed');
                                        var wbBlue = document.getElementById('wbBlue');
                                        var wbRedVal = document.getElementById('wbRedVal');
                                        var wbBlueVal = document.getElementById('wbBlueVal');
                                        if (wbRed) { wbRed.value = ev.final_red; if (wbRedVal) wbRedVal.textContent = ev.final_red; }
                                        if (wbBlue) { wbBlue.value = ev.final_blue; if (wbBlueVal) wbBlueVal.textContent = ev.final_blue; }
                                    } else {
                                        var rollMsg = ev.rollback_steps ? ' (回滚' + ev.rollback_steps + '步)' : '';
                                        showToast('success', label + '完成 反差=' + ev.final_contrast + rollMsg);
                                        operationLog('── ' + label + '完成: 反差=' + ev.final_contrast + rollMsg + ' (' + ev.total_steps + '步) ──', 'success');
                                    }
                                } else if (ev.type === 'cleanup') {
                                    operationLog('清理完成', 'info');
                                } else if (ev.type === 'error') {
                                    operationLog(label + '失败: ' + ev.message, 'error');
                                    showToast('error', label + '失败');
                                }
                            } catch(e) { /* 跳过损坏的 JSON */ }
                        }
                        return pump();
                    });
                }
                return pump();
            })
            .catch(function(e) {
                operationLog(label + '异常: ' + e.message, 'error');
                showToast('error', '异常: ' + e.message);
            });
    }

    function _resetRegionUI() {
        _regionMode = null;
        var btnWB = document.getElementById('btnRegionWB');
        var btnAF = document.getElementById('btnRegionAF');
        var overlay = document.getElementById('regionOverlay');
        var box = document.getElementById('regionBox');
        if (btnWB) btnWB.className = 'btn btn-secondary btn-sm';
