    function toggleRegionMode(mode) {
        // 新的按钮 ID（在白平衡/对焦局部控制中）
        var btnWB = document.getElementById('btnWbRegionSelect');
        var btnAF = document.getElementById('btnFocusRegionSelect');
        var overlay = document.getElementById('regionOverlay');
        var box = document.getElementById('regionBox');
        if (_regionMode === mode) {
            _regionMode = null;
            if (btnWB) btnWB.className = 'btn btn-secondary btn-sm';
            if (btnAF) btnAF.className = 'btn btn-secondary btn-sm';
            overlay.style.display = 'none';
            box.style.display = 'none';
            return;
        }
        if (!window.connectedDevice || !window.connectedDevice.ip) {
            showToast('warning', '请先连接设备');
            return;
        }
        // v8.39: 移除手动模式限制 - 局部模式自动切换到手动
        // 当选择局部框选时，自动切换到手动模式
        if (mode === 'whitebalance') {
            var wbMode = document.getElementById('wbMode');
            if (wbMode && wbMode.value !== 'manual') {
                // 自动切换到手动模式
                setWhiteBalanceMode('manual');
            }
        }
        if (mode === 'focus') {
            var fm = document.getElementById('focusMode');
            if (fm && fm.value !== 'manual') {
                // 自动切换到手动模式
                setFocusMode('manual');
            }
        }
        _regionMode = mode;
        if (btnWB) btnWB.className = mode === 'whitebalance' ? 'btn btn-primary btn-sm' : 'btn btn-secondary btn-sm';
        if (btnAF) btnAF.className = mode === 'focus' ? 'btn btn-primary btn-sm' : 'btn btn-secondary btn-sm';
        overlay.style.display = 'block';
        box.style.display = 'none';
    }

